var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"왔는가. 레아 슈나이더.","JPN":"来たか、レア・シュナイダー。","ENG":"You are here, Leah Schneider.","TWN":"你來了，蕾亞·修奈德。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네. 하지만 여자를 혼자 내버려 두고 훌쩍 떠나가 버리다니, 매너가 없네요.","JPN":"はい、それにしても、女性一人を置いてふらっといなくなるなんて失礼ですね。","ENG":"Yes. But how rude of you to leave a lady all alone.","TWN":"對，你竟然丟下女生自己跑掉，很沒風度欸。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너와 사연이 있는 인물이라고 여겨 잠시 자리를 내 주었을 뿐이다.","JPN":"そなたが二人きりで話したい人物だろうと思い、しばらく外していただけだ。","ENG":"I simply provided some privacy because I deemed her story important to you.","TWN":"我知道那個人和你之間發生過很多事，所以才給你們獨處的時間。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이야기는 충분히 나누었나?","JPN":"話はできたか？","ENG":"Have you exchanged words?","TWN":"聊得盡興嗎？"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"덕분에요. 조금은 기운을 차렸다고나 할까요.","JPN":"おかげさまで。少しは元気になったと言いますか。","ENG":"Yes, thanks to you. I'm feeling a bit better.","TWN":"嗯，托你的福，我好像有稍微恢復一些活力。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이 열차에 모여 있는 것들은…. 모두 네퀴티아가 겪었던 실패의 경험일 거예요.","JPN":"この列車に集められているのは……すべてネキティアが経験してきた失敗の数々なんだと思います。","ENG":"I think... everything in this train is the experience of Nequitia's failure.","TWN":"這列車裡的一切…都是莉奎蒂亞經歷過的失敗。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"몽타뉴도, 결국 그 때 끝장을 내지 못하는 바람에 귀찮게 된 상대였으니까.","JPN":"モンターニュも結局、あの時トドメを刺さなかったせいで面倒なことになった相手ですからね。","ENG":"Montagne, too, was someone who became a problem later on because she couldn't finish her off at first.","TWN":"譬如蒙塔妮，是因為當時一時心軟而留下的遺毒。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 저에게는 그렇지 않아요.","JPN":"でも私にとってはそうじゃありません。","ENG":"But that isn't how I see it.","TWN":"但對我來說並非如此。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"적의 생명을 구해 줬다는 건, 저에게 무른 면이 있다는 상징이나 마찬가지니까요.","JPN":"敵の命を奪わなかったことは、自分に甘い側面があるという証拠のようなものですから。","ENG":"Sparing the life of an enemy means that I have a soft side too.","TWN":"留下敵人的性命，就說明我的內心還保留著柔軟的一面。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너와 그녀가 다르다고 말하고 싶은 것인가.","JPN":"そなたと彼女は違うと言いたいのか。","ENG":"Do you wish to say that you are different from her?","TWN":"你是想說，你和她不一樣。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"맞아요. 그래서 저도 여기 있는 것 아닐까요?","JPN":"はい。だから私は今ここにいるんじゃないでしょうか？","ENG":"Yes. Maybe that's why I'm in here too.","TWN":"沒錯。所以我才會站在這裡，不是嗎？"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"오히려 의문스러운 건 그쪽이에요. 에클레시아.","JPN":"むしろ怪しいのはそっちです。エクレシア。","ENG":"Rather, you're the one I'm not sure about, Ecclesia.","TWN":"我有疑問的反而是你，艾可露西亞。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그 성전에서 탈출하기 전에 셰나에게 들었거든요. 당신에 대해서.","JPN":"あの聖殿から逃げる前に、シェナから聞いたんです。あなたについて。","ENG":"I heard about you. From Shena, before I escaped the temple.","TWN":"從聖殿逃出來之前，世娜說了有關你的事情。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"꽤나 대접 받던 몸이었던 것 같은데, 어쩌다 이 열차에 갇히게 된 거죠?","JPN":"かなり高い地位にあったようですけど、どうしてこの列車に閉じ込められたんですか？","ENG":"Seems like you were in a pretty good position. How did you end up trapped on this train?","TWN":"你應該曾經是一個蠻有地位的人，為什麼會被困在這台列車裡？"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 질문에 대한 답은 다음 객차에 있을 터.","JPN":"その質問への答えは次の客車にあるはずだ。","ENG":"The next passenger vehicle should hold the answer to that question.","TWN":"答案就在下一節車廂裡。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"말보다는 직접 보여 주는 편이 설명에 용이하겠지.","JPN":"言葉より直接見せた方が説明しやすいだろう。","ENG":"It would be more convenient to show you than to tell you.","TWN":"我說再多都沒用，不如你親自去看看。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"독실한 성도들도 내 설교는 반기지 않았으니.","JPN":"敬虔な信徒でも、我の説教を望みはしなかった。","ENG":"Even my devout followers did not welcome my lectures.","TWN":"畢竟連那些虔誠的信徒也不樂意聽我的教訓。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"알면 그 딱딱한 말투부터 고치는 편이 어때요?","JPN":"自覚があるなら、その堅苦しい言い方から改めたらどうですか？","ENG":"If you're aware of that, how about you start changing the way you speak?","TWN":"你也知道喔？那還是改一下你那一板一眼的語氣？"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너와 같이 상스러운 말투를 쓰라는 제안이라면 정중히 사양하겠다.","JPN":"そなたのような下品な言葉遣いをしろという意味なら丁重に断ろう。","ENG":"I will have to decline if you are suggesting that I speak profanely like yourself.","TWN":"像你那樣輕浮的語氣嗎？恕我拒絕。"},"stage":{"bg":"TRAIL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"타기리온을 쓰러뜨리기 위한 원정 중에, 헤어진 가족을 찾고 있던 이교도 아이와 만났다.","JPN":"タギリオンを倒すための遠征の途中、離散した家族を探し回っている異教徒の子どもに出会った。","ENG":"During my expedition to defeat Thagirion, I met a pagan child who was looking for their lost family.","TWN":"我出征去討伐塔基里翁的途中，遇見一個尋找失散家人的異教徒孩子。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"이교도임에도 성흔을 지녔기에 시종으로 거두어들였고.","JPN":"異教徒ではあったが聖痕を持っていたため、侍従として迎え入れた。","ENG":"Although a pagan, she possessed a Stigmata, so I took her in as a servant.","TWN":"她雖然是異教徒，卻擁有聖痕，於是我決定把她留在我身邊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"타기리온을 쓰러뜨릴 때에 실로 크게 공헌하였다.","JPN":"タギリオンを倒した際には、大きく役立ってくれた。","ENG":"She contributed greatly to defeating Thagirion.","TWN":"在擊敗塔基里翁的事上，她確實有很大的貢獻。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"휴우…….","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L40_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"됐다. 아무에게도 안 들키고 들어왔어.","JPN":"よし、誰にもバレずに入ってこれた。","ENG":"I did it. I came in without anybody seeing me.","TWN":"好險，幸好沒被別人發現。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"예하께서는 언니가 어디 있는지 찾아 주겠다고 하셨지만….","JPN":"猊下はお姉ちゃんを見つけてくれると言ってくれたけど……","ENG":"Her Eminence told me she'd find where sis is...","TWN":"雖然主教答應會幫我尋找姊姊的下落…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"항상 도움만 받을 수는 없으니까.","JPN":"いつも助けてもらってばかりじゃダメだよね。","ENG":"But I can't always rely on others.","TWN":"但我總不能一直靠她的幫忙。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"그런데 이교도들을 데려와서 개종시키는 곳이라더니… 왜 이렇게 으스스하지?","JPN":"異教徒を連れてきて改宗させる場所だって聞いていたけど……なんでこんなに怖い雰囲気なんだろう？","ENG":"I heard this was where pagans were brought to be converted... but why is it so creepy?","TWN":"不過，這裡不是把異教徒帶過來洗腦的地方嗎……怎麼陰森森的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"앗, 사람?","JPN":"あっ、誰か来た！","ENG":"Oh, is anyone here?","TWN":"喔，有人？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"드, 들키면 화형대로 끌려갈 거야! 숨어야 돼!","JPN":"ば、バレたら火刑台に連れていかれちゃう！　隠れなきゃ！","ENG":"I-I'm going to be burnt at the stake if they find me here! I gotta hide!","TWN":"被…被發現的話會判火刑的！我要趕快躲起來！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"실험 경과는 순조롭습니다, 지휘자님. 새롭게 작성한 악보가 효과가 있어요.","JPN":"実験の経過は順調です、マエストロ。新しく作成した楽譜の効果がありました。","ENG":"Tests are going smoothly, Chief Conductor. The new music score is working.","TWN":"實驗非常順利，指揮家。新完成的樂譜效果很好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"추기경들께서 위험을 감수하고 지원해 주셨으니, 마땅히 성취를 얻어야지요.","JPN":"枢機卿の方々が危険を顧みず志願してくださったのですから、相応の成果を出せたのでしょう。","ENG":"The cardinals have volunteered despite the risks. Progress is deserved.","TWN":"樞機主教們可是冒著危險幫我們的，當然必須要有所成績。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"저 목소리는……? 악단 사람들이 왜 여기에 있는 거지?","JPN":"あの声は……？　楽団の人たちがなんでここにいるの？","ENG":"That voice...? Why are the Orchestra people here?","TWN":"這聲音是……？樂團的人們為什麼會來這裡？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"게다가 신전 지하에서 실험 얘기라니….","JPN":"しかも神殿の地下で実験の話をしているなんて……","ENG":"And, talking about tests in the basement of the temple...","TWN":"而且竟然在神殿地下室談論實驗……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음, 물론 그렇죠.","JPN":"それはもちろん。","ENG":"Hmm, of course.","TWN":"是，那是當然。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"예하께서도 물러나셨으니 이제 연구에 전념할 일만 남았네요.","JPN":"猊下も退位されたことですし、これで研究に専念できますね。","ENG":"Her Eminence has stepped down, so now we have to direct all our energy into research.","TWN":"既然主教已經離開，那我們要把所有精力放在研究上面。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그래요.","JPN":"そうですね。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"우리는 모두 손에 피를 묻힌 죄인입니다. 그러니 더욱 주어진 사명에 헌신해야지요.","JPN":"私たちは血塗られた罪人です。ですからより懸命に使命を全うべきです。","ENG":"We are all sinners with blood on our hands. We must devote ourselves to our duties even further.","TWN":"我們都是罪人，手上沾滿鮮血，所以更應該為自己的使命獻出所有。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"여전히 독실하시단 말이죠….","JPN":"信仰深いことで……","ENG":"Devout, as always...","TWN":"你依然如此虔誠……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"실험 규모가 커지면 새로운 시설이 필요할 거예요. 여기 있는 표본들은 어떻게 할까요?","JPN":"実験の規模が大きくなれば、新しい施設が必要になると思います。ここにある標本はどうしますか？","ENG":"We will need a new facility once the tests are conducted at a larger scale. What shall we do with the samples here?","TWN":"等實驗規模擴大後，我們需要建造一個新的設施，這裡的標本該如何處理呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"옮기기에는 보는 눈이 많습니다. 자칫 교단의 명예를 실추시킬 수도 있겠지요.","JPN":"どこかに運ぶには見られる可能性が大きすぎます。下手をしたら教団の名誉を失墜させかねません。","ENG":"There are too many prying eyes around. The Order's reputation could potentially be tarnished.","TWN":"搬運的話有洩露的風險，會害得教團名譽掃地。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"자료는 충분히 확보하였으니, 폐기하도록 하세요.","JPN":"資料は十分に確保できましたから、廃棄してください。","ENG":"We have secured sufficient research materials. Dispose of this place.","TWN":"我們手邊的資料已經足夠，把剩下的都扔掉吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"휴우…. 다행이다. 들키지 않았어.","JPN":"ふう……よかった。バレなかった。","ENG":"Phew... That was close, but I wasn't found.","TWN":"呼…幸好沒被發現。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"저 사람들이랑 마주쳤다간 예하께도 불똥이 튈 거야. 곧 성황이 되실 분인데….","JPN":"あの人たちにバレたら、猊下にも被害が及んでしまう。もう少しで聖皇になられるお方なのに……","ENG":"If I run into them here, Her Eminence might be held responsible too. That can't happen, she's to become a pope soon...","TWN":"要是被她們發現，主教也會受到牽連。她可是要成為聖皇的人……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"아얏!","JPN":"いたっ！","ENG":"Ouch!","TWN":"哎呀！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"으으, 머리야. 어두워서 그만……","JPN":"うう、頭痛い。暗くて見えなかった……","ENG":"Ow, my head. It's so dark...","TWN":"嗚嗚，好痛喔。這裡好暗，我還是……"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"……어?","JPN":"……あっ？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"음…? 지정된 시각 이외에 설비는 사용해선 안 된다고 교육하지 않았나요?","JPN":"うん……？　指定の時間以外には設備に触れてはいけないと教育しませんでしたか？","ENG":"Hmm...? I thought you were all taught not to use the equipment outside of the designated time.","TWN":"嗯…？我不是說過指定時間外禁止使用設備嗎？"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"누구야! 누가 허락 없이 기기들을 작동시켰어!","JPN":"誰だ！　誰か勝手に機器を作動させている！","ENG":"Who was that?! Who activated the equipment without permission?!","TWN":"是誰！是誰擅自啟動機器！"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"This...","TWN":"這……"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"이름이, 적혀 있네……?","JPN":"名前が、書いてある……？","ENG":"has a name, on it…?","TWN":"這上面有寫名字……？"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"침입자일지도 몰라! 다들 흩어져서 찾아!","JPN":"侵入者かもしれない！　みんな手分けして探して！","ENG":"It might be an intruder! Everyone, scatter and find whoever it is!","TWN":"可能有人闖進來！大家分頭去找！"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"……언니.","JPN":"……お姉ちゃん。","ENG":"...Sis.","TWN":"……姊姊。"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"언니야? 정말, 언니 맞아?","JPN":"お姉ちゃん？　本当にお姉ちゃんなの？","ENG":"Sis? Is this really you, sis?","TWN":"姊姊？真的是你嗎，姊姊？"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"셰나님! 침입자를 찾았습니다!","JPN":"シェナ様！　侵入者を見つけました！","ENG":"We found the intruder, ma'am!","TWN":"世娜！找到入侵者了！"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"아, 아아…….","JPN":"あ、ああ……","ENG":"Ah... Aaaah...","TWN":"啊啊啊……"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L34_1","type":"dialog","speaker":"DASH_HORIZON_EX_NULL","text":{"KOREA":"아아아아아……!","JPN":"あああああ……！","ENG":"Aaaaaagh...!","TWN":"啊啊啊啊……！"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"마왕과 대적자에 대해 알게 된 것은 먼 훗날의 일이었다.","JPN":"魔王と敵対者について知ったのは、ずっと先のことだった。","ENG":"It was in the distant future that I was made aware of the Demon Lord and the Antagonist.","TWN":"至於我知道到魔王和對敵者的事，都已經是很久以後的事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"그 아이가, 무엇이었는지에 대해서도.","JPN":"あの子が、何だったのかについても。","ENG":"And of what that child was.","TWN":"那孩子的身分也是。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};